form:Form.form:Scripts:
		var g_OC=null;               //Cache de QUERY               
var g_mode;                  //0: All/completo, 1: All/estructura, 2: Solo/estructura
var g_oi_estr1_show =null;   //Modo Organigrama
var g_oi_estr2_show =null;   //Modo Estructura
var g_oi_estr_root  =null;   //Estructura Raiz
var g_oi_estr_select=null;   //Estructura Seleccionada
var g_oi_legajo_select=null; //Legajo Seleccionado
var g_deep=3;                //Cantidad de Niveles
var g_lst_Estr=null;         //Lista de Estructuras Visibles
var g_stack=new Array();     //Stack de Navegacion entre estructuras

function OrgGetCache(MODE, KEY)
{                                     
	var objMODE;
	if (g_OC==null) g_OC=new Array(); 
	objMODE=g_OC[MODE];	if (objMODE?false:true) objMODE=g_OC[MODE]=new Array();
	return objMODE[KEY]?objMODE[KEY]:null;
}       

function OrgAddCache(MODE, KEY, OBJ)
{
	var objMODE;
	if (g_OC==null) g_OC=new Array(); 
	objMODE=g_OC[MODE];	if (objMODE?false:true) objMODE=g_OC[MODE]=new Array();
	objMODE[KEY]=OBJ;
}       

function OrgClearCache()
{
	g_OC=new Array(); 
}       

function QueryCache(Name, Param)
{
	 var rv=OrgGetCache(Name,Param);
	 if (rv!=null) return rv;

	 rv = GetProxy().SQLService().GetXML(Ctrl("main").getResource(Name), Param);

	 OrgAddCache(Name,Param,rv);
	 return rv;
}

function LoadOrg(oi_estructura,deep)
{                  
	return QueryCache("qry:ORGANIGRAMA_SIMPLE", '<PARAM oi_estructura="'+oi_estructura+'" deep="'+deep+'" />');
}                             

function LoadEstr(oi_estructura,oi_estructura_root)
{                               
	return QueryCache("qry:ORGANIGRAMA", '<PARAM oi_estructura="'+oi_estructura+'" oi_estructura_root="'+oi_estructura_root+'" />');
}                                  

function GetHTMLSimple(oi_estructura, deep)
{  
	return Replace(GenerarHTMLUnidadAll(LoadOrg(oi_estructura,deep),true),"{nbsp}","&nbsp;");
}

function GetHTMLEstruct(oi_estructura)
{
	return Replace(GenerarHTMLUnidad(LoadEstr(oi_estructura,g_oi_estr_root)),"{nbsp}","&nbsp;");
}

function Normalize(strin)
{
	var retstr;                                 
	retstr=strin;
	retstr=Replace(retstr," ","&nbsp;")
	return retstr; 
}

function GenerateHTMLDivSimple(uniTree)
{
	var TextDiv, MyIMG, imgName;

	g_lst_Estr["K"+uniTree.GetAttr("oi_estructura")]=uniTree;

	if (uniTree.GetAttr("fic")=="1")
	{                                                     
		if (uniTree.GetAttr("oi_estructura")==g_oi_estr_select) TextDiv=Ctrl("main").getResource("html:DIV_SIMPLE_FIC_SEL");   
		                                                   else TextDiv=Ctrl("main").getResource("html:DIV_SIMPLE_FIC");   

		TextDiv=Replace(TextDiv, "{UNIDAD}",Normalize(uniTree.GetAttr("unidad")==""?"-":uniTree.GetAttr("unidad")));
		TextDiv=Replace(TextDiv, "{OI_ESTRUCTURA}",uniTree.GetAttr("oi_estructura"));
	} else 
	if (uniTree.GetAttr("l_staff")=="1")
	{
		TextDiv=Ctrl("main").getResource("html:DIV_SIMPLE_STAFF");   
		TextDiv=Replace(TextDiv, "{UNIDAD}",Normalize(uniTree.GetAttr("unidad")==""?"-":uniTree.GetAttr("unidad")));
		TextDiv=Replace(TextDiv, "{OI_ESTRUCTURA}",uniTree.GetAttr("oi_estructura"));
		TextDiv=Replace(TextDiv, "{OI_LEGAJO}",uniTree.GetAttr("oi_legajo")==""?"null":uniTree.GetAttr("oi_legajo"));
	} else
	if (uniTree.GetAttr("nombre")!="")
	{
		TextDiv=Ctrl("main").getResource("html:DIV_SIMPLE"+(uniTree.GetAttr("Vista")!=""?"_VISTA":""));
		TextDiv=Replace(TextDiv, "{UNIDAD}"       ,Normalize(uniTree.GetAttr("unidad")==""?"-":uniTree.GetAttr("unidad")));
		TextDiv=Replace(TextDiv, "{NOMBRE}"       ,Normalize(uniTree.GetAttr("nombre")==""?"-":uniTree.GetAttr("nombre")));
		TextDiv=Replace(TextDiv, "{EMPRESA}"      ,Normalize(uniTree.GetAttr("empresa")==""?"-":uniTree.GetAttr("empresa")));
		TextDiv=Replace(TextDiv, "{LEGAJO}"       ,Normalize(uniTree.GetAttr("legajo")==""?"-":uniTree.GetAttr("legajo")));
		TextDiv=Replace(TextDiv, "{E_MAIL}"       ,Normalize(uniTree.GetAttr("mail")==""?"-":uniTree.GetAttr("mail")));
		TextDiv=Replace(TextDiv, "{OI_ESTRUCTURA}",uniTree.GetAttr("oi_estructura"));
		TextDiv=Replace(TextDiv, "{OI_LEGAJO}"    ,uniTree.GetAttr("oi_legajo"));
		TextDiv=Replace(TextDiv, "{OI_PESONAL}"   ,uniTree.GetAttr("oi_pesonal"));

		if (uniTree.GetAttr("foto")!="")
		{
		    var crc = CRC32("PARAMS:mode=DB|class=NucleusRH.Base.Personal.Imagenes.HEAD|id="+ uniTree.GetAttr("foto"));
			imgName="../../../NomadFile.aspx?ut="+GetProxy().UserToken()+"&mode=DB&class=NucleusRH.Base.Personal.Imagenes.HEAD&id="+uniTree.GetAttr("foto")+"&width=48&height=48&crc="+crc;
		} else
		{        
			imgName="../images/organigrama/defaultimg.JPG";
		} 
		TextDiv=Replace(TextDiv, "{FOTO}",imgName);

	} else             
	if (uniTree.GetAttr("extern")!="")
	{
		TextDiv=Ctrl("main").getResource("html:DIV_SIMPLE_EXTERN");
		TextDiv=Replace(TextDiv, "{UNIDAD}",Normalize(uniTree.GetAttr("unidad")==""?"-":uniTree.GetAttr("unidad")));
		TextDiv=Replace(TextDiv, "{OI_ESTRUCTURA}" ,uniTree.GetAttr("oi_estructura"));
		TextDiv=Replace(TextDiv, "{OI_LEGAJO}"     ,uniTree.GetAttr("oi_legajo")==""?"null":uniTree.GetAttr("oi_legajo"));
		TextDiv=Replace(TextDiv, "{OI_CLASE_ORG}"  ,uniTree.GetAttr("oi_clase_org"));
		TextDiv=Replace(TextDiv, "{OI_CLASE_HIJA}" ,uniTree.GetAttr("oi_clase_hija"));
		TextDiv=Replace(TextDiv, "{OI_ESTR_PARENT}",uniTree.GetAttr("oi_estr_parent"));
	} else
	{
		TextDiv=Ctrl("main").getResource("html:DIV_SIMPLE_NORESP"+(uniTree.GetAttr("Vista")!=""?"_VISTA":""));
		TextDiv=Replace(TextDiv, "{UNIDAD}",Normalize(uniTree.GetAttr("unidad")==""?"-":uniTree.GetAttr("unidad")));
		TextDiv=Replace(TextDiv, "{OI_ESTRUCTURA}",uniTree.GetAttr("oi_estructura"));
		TextDiv=Replace(TextDiv, "{OI_LEGAJO}",uniTree.GetAttr("oi_legajo")==""?"null":uniTree.GetAttr("oi_legajo"));
	}  

	if (uniTree.GetAttr("oi_estructura")==g_oi_estr_select)
	{      
		TextDiv=Replace(TextDiv,"url(../images/organigrama/unidad1.jpg)","url(../images/organigrama/unidad3.jpg)");
		TextDiv=Replace(TextDiv,"url(../images/organigrama/unidad2.jpg)","url(../images/organigrama/unidad3.jpg)");
	}

	return TextDiv;

}

function GenerarHTMLUnidadAll(uniTree, isRoot)
{
	var TextTable, SubTable, auxTable, t, m, cur;


	TextDiv=GenerateHTMLDivSimple(uniTree);

	m=-1;
	if (uniTree.FindElement("unidades")!=null) 
		for (cur=uniTree.FindElement("unidades").FirstChild(); cur!=null; cur=cur.Next()) 
			if (cur.GetAttr("l_staff")!="1") 
				m++;

	if (uniTree.FindElement("externas")!=null)				
		for (cur=uniTree.FindElement("externas").FirstChild(); cur!=null; cur=cur.Next()) 
			m++;


	if (m!=-1)
	{                           
		if (isRoot && uniTree.GetAttr("oi_estructura")!=g_oi_estr_root.toString())
			TextTable=Ctrl("main").getResource("html:TABLABASE_SIMPLE_PARENTHIDE");   
		else                                                            
			TextTable=Ctrl("main").getResource("html:TABLABASE_SIMPLE");   
		TextTable=Replace(TextTable, "{DIV SIMPLE}",TextDiv);
		TextTable=Replace(TextTable, "{OI_ESTRUCTURA}",uniTree.GetAttr("oi_estructura"));
		TextTable=Replace(TextTable, "{OI_ESTR_PADRE}",uniTree.GetAttr("oi_estr_padre"));
		TextTable=Replace(TextTable, "{OI_LEGAJO}",uniTree.GetAttr("oi_legajo")==""?"null":uniTree.GetAttr("oi_legajo"));

		for (cur=uniTree.FindElement("unidades").FirstChild(); cur!=null; cur=cur.Next()) 
			if (cur.GetAttr("l_staff")=="1")
			{
				TextTable=Replace(TextTable, "{STAFF}",GenerateHTMLDivSimple(cur,false));
				TextTable=Replace(TextTable, "{NO-STAFF}",Ctrl("main").getResource("html:DIV_SIMPLE_NO_STAFF"));
				break;
			}
		TextTable=Replace(TextTable, "{STAFF}","&nbsp;");
		TextTable=Replace(TextTable, "{NO-STAFF}","&nbsp;");

		SubTable="";
		for (t=0; t<=m; t++)
		{          
			if (t==0)	SubTable+=Ctrl("main").getResource("html:LINE00");
			     else SubTable+=Ctrl("main").getResource("html:LINE01");

			if (t==m)	SubTable+=Ctrl("main").getResource("html:LINE11");
			     else SubTable+=Ctrl("main").getResource("html:LINE10");
		}
		TextTable=Replace(TextTable, "{LINEAS}",SubTable);



		if (uniTree.FindElement("unidades")!=null) 
		{
			SubTable=""; 
			for (cur=uniTree.FindElement("unidades").FirstChild(); cur!=null; cur=cur.Next()) 
				if (cur.GetAttr("l_staff")!="1")
				{
					auxTable=Ctrl("main").getResource("html:TABLASUB_SIMPLE");
					auxTable=Replace(auxTable, "{UNIDAD}",GenerarHTMLUnidadAll(cur,false));

					SubTable+=auxTable;
				}
		} 

		if (uniTree.FindElement("externas")!=null) 
		{
			for (cur=uniTree.FindElement("externas").FirstChild(); cur!=null; cur=cur.Next()) 
			{                               
				auxTable=Ctrl("main").getResource("html:TABLASUB_SIMPLE");
				auxTable=Replace(auxTable, "{UNIDAD}",GenerarHTMLUnidadAll(cur,false));

				SubTable+=auxTable;
			}
		}
		TextTable=Replace(TextTable, "{ORGANIGRAMAS HIJOS}",SubTable);
	} else
	{         
		var staff=null;
		if (uniTree.FindElement("unidades")!=null) 
			for (cur=uniTree.FindElement("unidades").FirstChild(); cur!=null; cur=cur.Next()) 
				if (cur.GetAttr("l_staff")=="1") 
					staff=cur;

	  if (staff!=null)
	  {         
			TextTable=Ctrl("main").getResource("html:TABLABASE_SIMPLE_STAFF");
			TextTable=Replace(TextTable, "{DIV SIMPLE}",TextDiv);
			TextTable=Replace(TextTable, "{OI_ESTRUCTURA}",uniTree.GetAttr("oi_estructura"));
			TextTable=Replace(TextTable, "{OI_ESTR_PADRE}",uniTree.GetAttr("oi_estr_padre"));
			TextTable=Replace(TextTable, "{OI_LEGAJO}",uniTree.GetAttr("oi_legajo")==""?"null":uniTree.GetAttr("oi_legajo"));
			TextTable=Replace(TextTable, "{STAFF}",GenerateHTMLDivSimple(staff));
	  } else
	  {        
			if (uniTree.GetAttr("child_count")!="0")
				TextTable=Ctrl("main").getResource("html:TABLABASE_SIMPLE_CHILDHIDE");
			else
			if (isRoot && uniTree.GetAttr("oi_estructura")!=g_oi_estr_root.toString())
				TextTable=Ctrl("main").getResource("html:TABLABASE_SIMPLE_NOCHILD_PARENTHIDE");
			else                                                                 
				TextTable=Ctrl("main").getResource("html:TABLABASE_SIMPLE_NOCHILD");


			TextTable=Replace(TextTable, "{DIV SIMPLE}",TextDiv);
			TextTable=Replace(TextTable, "{OI_ESTRUCTURA}",uniTree.GetAttr("oi_estructura"));
			TextTable=Replace(TextTable, "{OI_ESTR_PADRE}",uniTree.GetAttr("oi_estr_padre"));
			TextTable=Replace(TextTable, "{OI_LEGAJO}",uniTree.GetAttr("oi_legajo")==""?"null":uniTree.GetAttr("oi_legajo"));
		}
	}  

	return TextTable;
}

function GenerarUnidad(uniTree)
{
	var TextTable, SubTable, auxTable, auxPER, t, MyIMG, imgName, personaResp, personaFirst;

	g_lst_Estr["K"+uniTree.GetAttr("oi_estructura")]=uniTree;

	personaResp=null; personaFirst=uniTree.FindElement("Personas").FirstChild();

	if (personaFirst!=null)
		if (personaFirst.GetAttr("resp")=="1") 
		{ 
			personaResp=personaFirst; 
			personaFirst=personaResp.Next(); 
		}

	if (personaResp!=null && personaFirst!=null)
		TextTable=Ctrl("main").getResource("html:TABLAUNIDAD");
	else
	if (personaResp!=null && personaFirst==null)
		TextTable=Ctrl("main").getResource("html:TABLAUNIDAD_NOCHILD");
	else
		TextTable=Ctrl("main").getResource("html:TABLAUNIDAD_CHILD");

	TextTable=Replace(TextTable,"{OI_ESTRUCTURA}",uniTree.GetAttr("oi_estructura"));
	TextTable=Replace(TextTable,"{UNIDAD}"       ,uniTree.GetAttr("unidad"));

	TextTable=Replace(TextTable,"{OI_PERSONAL}",(personaResp && personaResp.GetAttr("oi_personal")?Normalize(personaResp.GetAttr("oi_personal")):""));
	TextTable=Replace(TextTable,"{OI_LEGAJO}"  ,(personaResp && personaResp.GetAttr("oi_legajo")  ?Normalize(personaResp.GetAttr("oi_legajo")  ):""));

	TextTable=Replace(TextTable,"{PUESTO}"     ,(personaResp && personaResp.GetAttr("puesto")     ?Normalize(personaResp.GetAttr("puesto")     ):"-"));
	TextTable=Replace(TextTable,"{POSICION}"   ,(personaResp && personaResp.GetAttr("posicion")   ?Normalize(personaResp.GetAttr("posicion")   ):"-"));
	TextTable=Replace(TextTable,"{EMPRESA}"    ,(personaResp && personaResp.GetAttr("empresa")    ?Normalize(personaResp.GetAttr("empresa")    ):"-"));
	TextTable=Replace(TextTable,"{LEGAJO}"     ,(personaResp && personaResp.GetAttr("legajo")     ?Normalize(personaResp.GetAttr("legajo")     ):"-"));
	TextTable=Replace(TextTable,"{NOMBRE}"     ,(personaResp && personaResp.GetAttr("nombre")     ?Normalize(personaResp.GetAttr("nombre")     ):"-"));
	TextTable=Replace(TextTable,"{MAIL}"       ,(personaResp && personaResp.GetAttr("mail")       ?Normalize(personaResp.GetAttr("mail")       ):"-"));
	TextTable=Replace(TextTable,"{TELEFONO}"   ,(personaResp && personaResp.GetAttr("telefono")   ?Normalize(personaResp.GetAttr("telefono")   ):"-"));

	if (personaResp && personaResp.GetAttr("foto")!="")
	{
		var crc = CRC32("PARAMS:mode=DB|class=NucleusRH.Base.Personal.Imagenes.HEAD|id="+ personaResp.GetAttr("foto"));
		imgName="../../../NomadFile.aspx?ut="+GetProxy().UserToken()+"&mode=DB&class=NucleusRH.Base.Personal.Imagenes.HEAD&id="+personaResp.GetAttr("foto")+"&width=100&height=100&crc="+crc;
	} else
	{        
		imgName="../images/organigrama/defaultimg.JPG";
	} 
	TextTable=Replace(TextTable,"{FOTO}",imgName);

	SubTable="";
	for (cur=personaFirst; cur!=null; cur=cur.Next())
	{

		if (cur.GetAttr("oi_legajo")==g_oi_legajo_select)
			auxTable=Ctrl("main").getResource("html:LINEABASE_SELECT");
		else                                                 
			auxTable=Ctrl("main").getResource("html:LINEABASE");


		auxTable=Replace(auxTable,"{OI_ESTRUCTURA}"  ,(uniTree.GetAttr("oi_estructura")?Normalize(uniTree.GetAttr("oi_estructura")):""));
		auxTable=Replace(auxTable,"{UNIDAD}"         ,(uniTree.GetAttr("unidad")       ?Normalize(uniTree.GetAttr("unidad")       ):"-"));

		auxTable=Replace(auxTable,"{OI_PERSONAL}"    ,(cur && cur.GetAttr("oi_personal")?Normalize(cur.GetAttr("oi_personal")):""));
		auxTable=Replace(auxTable,"{OI_LEGAJO}"      ,(cur && cur.GetAttr("oi_legajo")  ?Normalize(cur.GetAttr("oi_legajo")  ):""));

		auxTable=Replace(auxTable,"{PUESTO}"         ,(cur && cur.GetAttr("puesto")     ?Normalize(cur.GetAttr("puesto")     ):"-"));
		auxTable=Replace(auxTable,"{POSICION}"       ,(cur && cur.GetAttr("posicion")   ?Normalize(cur.GetAttr("posicion")   ):"-"));
		auxTable=Replace(auxTable,"{EMPRESA}"        ,(cur && cur.GetAttr("empresa")    ?Normalize(cur.GetAttr("empresa")    ):"-"));
		auxTable=Replace(auxTable,"{LEGAJO}"         ,(cur && cur.GetAttr("legajo")     ?Normalize(cur.GetAttr("legajo")     ):"-"));
		auxTable=Replace(auxTable,"{NOMBRE}"         ,(cur && cur.GetAttr("nombre")     ?Normalize(cur.GetAttr("nombre")     ):"-"));
		auxTable=Replace(auxTable,"{MAIL}"           ,(cur && cur.GetAttr("mail")       ?Normalize(cur.GetAttr("mail")       ):"-"));
		auxTable=Replace(auxTable,"{TELEFONO}"       ,(cur && cur.GetAttr("telefono")   ?Normalize(cur.GetAttr("telefono")   ):"-"));

		SubTable+=auxTable;
	}
	TextTable=Replace(TextTable, "{LISTA DE CHILDS}",SubTable);

	if (uniTree.GetAttr("oi_estructura")==g_oi_estr_select)
	{      
		TextTable=Replace(TextTable,"url(../images/organigrama/unidad4.jpg)","url(../images/organigrama/unidad6.jpg)");
		TextTable=Replace(TextTable,"url(../images/organigrama/unidad5.jpg)","url(../images/organigrama/unidad6.jpg)");
	}
	return TextTable;
}

function GenerarHTMLUnidad(uniTree)
{
	var TextTable, SubTable, auxTable, t, cur;

	TextTable=Ctrl("main").getResource("html:TABLABASE");
	TextTable=Replace(TextTable, "{UNIDAD}",GenerarUnidad(uniTree));

	if (uniTree.FindElement("oi_estr_padre")==null || uniTree.GetAttr("oi_estructura")==g_oi_estr_root.toString())
		SubTable=Ctrl("main").getResource("html:NO_PARENT");
	else
		SubTable=GenerateHTMLDivSimple(uniTree.FindElement("oi_estr_padre"));	
	TextTable=Replace(TextTable,"{DIV PARENT SIMPLE}",SubTable);


	for (cur=uniTree.FindElement("unidades").FirstChild(); cur!=null; cur=cur.Next())
		if (cur.GetAttr("l_staff")=="1") 
		{ 
			TextTable=Replace(TextTable, "{STAFF}",GenerateHTMLDivSimple(cur));
			TextTable=Replace(TextTable, "{NO-STAFF}",Ctrl("main").getResource("html:DIV_SIMPLE_NO_STAFF"));
			break;
		}
	TextTable=Replace(TextTable, "{STAFF}","&nbsp;");
	TextTable=Replace(TextTable, "{NO-STAFF}","&nbsp;");

	SubTable=""; m=-1;
	if (uniTree.FindElement("unidades")!=null) 
		for (cur=uniTree.FindElement("unidades").FirstChild(); cur!=null; cur=cur.Next()) 
			if (cur.GetAttr("l_staff")!="1") 
				m++;

	if (uniTree.FindElement("externas")!=null)				
		for (cur=uniTree.FindElement("externas").FirstChild(); cur!=null; cur=cur.Next()) 
			m++;

	for (t=0; t<=m; t++)
	{          
		if (t==0)	SubTable+=Ctrl("main").getResource("html:LINE00");
		     else SubTable+=Ctrl("main").getResource("html:LINE01");

		if (t==m)	SubTable+=Ctrl("main").getResource("html:LINE11");
		     else SubTable+=Ctrl("main").getResource("html:LINE10");
	}	
	TextTable=Replace(TextTable,"{LINEAS}",SubTable);

	if (m!=-1)
	{
		SubTable=""; 
		if (uniTree.FindElement("unidades")!=null)
			for (cur=uniTree.FindElement("unidades").FirstChild(); cur!=null; cur=cur.Next()) 
				if (cur.GetAttr("l_staff")!="1")
				{          
					auxTable=Ctrl("main").getResource("html:TABLASUB");
					auxTable=Replace(auxTable, "{UNIDAD}",GenerateHTMLDivSimple(cur));

					SubTable+=auxTable;
				}

		if (uniTree.FindElement("externas")!=null)
			for (cur=uniTree.FindElement("externas").FirstChild(); cur!=null; cur=cur.Next()) 
			{                               
				auxTable=Ctrl("main").getResource("html:TABLASUB");
				auxTable=Replace(auxTable, "{UNIDAD}",GenerateHTMLDivSimple(cur));

				SubTable+=auxTable;
			}

	} else
		SubTable=Ctrl("main").getResource("html:NO_CHILD");


	TextTable=Replace(TextTable, "{ORGANIGRAMAS HIJOS}",SubTable);			               
	TextTable=Replace(TextTable,"{nbsp}","&nbsp;");

	return TextTable;
}

function DrawHTML()
{
	var HTML;       

	g_lst_Estr=new Array();
	switch(g_mode)
	{
		case 0: //All/completo   
			HTML=GetHTMLSimple(g_oi_estr_root , 100000);
		break;

		case 1: //All/estructura
			HTML=GetHTMLSimple(g_oi_estr1_show, g_deep);
		break;                             

		case 2: //Solo/estructura
			HTML=GetHTMLEstruct(g_oi_estr2_show);
		break;
	}

	Ctrl("contORG").SetInner(HTML);

	ButtonRefresh();
}                 

function OnLoad()
{              
	//Estado
	if (Ctrl("oi_estructura_root").GetXValue()!="")
	{
		g_mode        =1; //All/estructura
		g_oi_estr_root=Ctrl("oi_estructura_root").GetXValue(); //Estructura RAIZ
		g_deep        =parseInt(Ctrl("deep").GetXValue(),10); //Cantidad de NIVELES
		Ctrl("estado").SetXValue(QueryCache("qry:ESTADO", '<PARAM oi_clase_org="'+Ctrl("oi_clase_org").GetXValue()+'"/>').GetAttr("c_estado"));	

	} else
	if (Ctrl("oi_clase_org").GetXValue()!="")
	{
		g_mode        =1; //All/estructura
		g_oi_estr_root=QueryCache("qry:ORGANIGRAMA_SIMPLE", '<PARAM oi_clase_org="'+Ctrl("oi_clase_org").GetXValue()+'" deep="1" />').GetAttrInt("oi_estructura"); //Estructura RAIZ
		g_deep        =10000; //Cantidad de NIVELES
		Ctrl("estado").SetXValue(QueryCache("qry:ESTADO", '<PARAM oi_clase_org="'+Ctrl("oi_clase_org").GetXValue()+'"/>').GetAttr("c_estado"));	
	} else
	{
		g_mode        = 1; //All/estructura
		g_oi_estr_root=107; //Estructura RAIZ
		g_deep        =10000; //Cantidad de NIVELES
		Ctrl("estado").SetXValue('V');	
	}

	g_oi_estr1_show=g_oi_estr_root;
	g_oi_estr2_show=g_oi_estr_root;
	DrawHTML();
}

function EstructuraDblClick(oi_estructura)
{
	var MyOBJ=null;            

	if (oi_estructura?false:true)            
	{
		oi_estructura=g_stack[g_stack.length-1];
		g_stack.length--;
	} else
		MyOBJ=g_lst_Estr["K"+oi_estructura];

	if (g_mode==2)                                   
	{
		g_oi_estr2_show   =oi_estructura;
		g_oi_estr_select  =null; //Estructura Seleccionada
		g_oi_legajo_select=null; //Legajo Seleccionado
		DrawHTML();
	} else
	{
		if (MyOBJ && MyOBJ.GetAttr("extern")=="1")   
			g_stack.push(g_oi_estr1_show);

		g_mode=1;                     
		g_oi_estr_select=null;
		g_oi_legajo_select=null;
		g_oi_estr1_show=oi_estructura;
		DrawHTML();
	}
}

function EstructuraClick(oi_estructura, oi_legajo)
{                                                                 
	if (g_oi_estr_select==oi_estructura && g_oi_legajo_select==oi_legajo) return;
	g_oi_estr_select=oi_estructura;                                  
	g_oi_legajo_select=oi_legajo;
	DrawHTML();
}


function ZoomIn()
{                
	Ctrl("contORG").ZoomIn();
}

function ZoomOut()
{                
	Ctrl("contORG").ZoomOut();
}

function ButtonRefresh()
{                           
	var MyOBJ=null;
	CtrlEnabled("ZOOM_IN" ,getBrowser()=="ie"?true:false);
	CtrlEnabled("ZOOM_OUT",getBrowser()=="ie"?true:false);
	CtrlEnabled("ALL" ,(g_mode==2)?true:false);

	MyOBJ=g_oi_estr_select?g_lst_Estr["K"+g_oi_estr_select]:null;
	if (MyOBJ && MyOBJ.GetAttr("fic")=="1")
	{
		CtrlEnabled("ESTR"  ,false);
		CtrlEnabled("PERS"  ,false);
		CtrlEnabled("SEARCH",false);
	} else
	{	
		CtrlEnabled("ESTR"  ,(g_mode!=2 && g_oi_estr_select!=null)?true:false);
		CtrlEnabled("PERS"  ,(g_mode!=2 && g_oi_estr_select!=null)?true:false);
		CtrlEnabled("SEARCH",(g_mode!=2 && g_oi_estr_select!=null)?true:false);
	}

	CtrlEnabled("PERSONA",g_oi_legajo_select==null?false:true);
	CtrlEnabled("LEGAJO" ,g_oi_legajo_select==null?false:true);
	CtrlEnabled("REPORTE",g_oi_legajo_select==null?false:true);

	ExternButtonRefresh();
}

function ExternButtonRefresh() {}


function Leg2Per(oi_legajo)
{
	var obj=QueryCache("qry:PERSONAL", '<PARAM oi_legajo="'+oi_legajo+'" />');
	return obj.GetAttr("oi_personal");
}

function ShowPersonal()
{                          
	var oi_personal=Leg2Per(g_oi_legajo_select);
	openNewFlowWait("NucleusRH.Base.Personal.Legajo.flow","ORGANIGRAMA",'<ID VALUE="'+oi_personal+'" />',new ObjtectResult(),"L");
}

function ShowLegajo()
{                      
	openNewFlowWait("NucleusRH.Base.Personal.LegajoEmpresa.flow","ORGANIGRAMA",'<ID VALUE="'+g_oi_legajo_select+'" />',new ObjtectResult(),"L");
}

function ShowReporte()
{
	openNewFlowWait("NucleusRH.Base.Personal.Reportes.Legajo.flow","ORGANIGRAMA",'<ID VALUE="'+g_oi_legajo_select+'" />',new ObjtectResult(),"L");
}

function ObjtectResult() { this.processResult= function(xmlin) { } }


function ShowOrganigrama()
{
	g_mode            =1; //All/estructura
	//g_oi_estr1_show   =g_oi_estr2_show;
	g_oi_estr_select  =null; //Estructura Seleccionada
	g_oi_legajo_select=null; //Legajo Seleccionado

	DrawHTML();
}

function ShowEstructura()
{
	g_mode            =2; //All/estructura
	g_oi_estr2_show   =g_oi_estr_select;
	g_oi_estr_select  =null; //Estructura Seleccionada
	g_oi_legajo_select=null; //Legajo Seleccionado

	DrawHTML();
}

function SearchResult() 
{ 
	this.processResult= function(xmlin) 
	{ 
		var rs=new NomadXML(xmlin); 
		if (rs.GetAttr("value")!="")
		{                     
			var MyOBJ=g_lst_Estr["K"+g_oi_estr_select];
			if (MyOBJ && MyOBJ.GetAttr("extern")=="1")   
				g_stack.push(g_oi_estr1_show);

			EstructuraDblClick(rs.GetAttrInt("value"),null);
		}
	} 
} 

function Buscar()
{                                                                                                                    
	if (g_oi_estr_select==null) return;
	openNewFlowWait("NucleusRH.Base.Organizacion.Clases_Organizativas.ESTRUCTURA.guia.flow","HELP",'<helper-mess id="'+g_oi_estr_select+'" oi_clase_org="'+g_lst_Estr["K"+g_oi_estr_select].GetAttr("oi_clase_org")+'" />',new SearchResult(),"L");
}

function ShowPersonas()
{                                   
	if (g_oi_estr_select==null) return;
	openNewFlowWait("NucleusRH.Base.Organizacion.Reportes.Organigrama.flow","personas",'<PARAM oi_estructura="'+g_oi_estr_select+'" />',new SearchResult(),"L");
}
